import React, { useState } from 'react';

function compute(a, b, op) {
  if (op === '+') return a + b;
  if (op === '-') return a - b;
  if (op === '*') return a * b;
  if (op === '/') return b === 0 ? NaN : a / b;
  return b;
}

export default function Calculator() {
  const [display, setDisplay] = useState('0');
  const [operand, setOperand] = useState(null);
  const [op, setOp] = useState(null);
  const [fresh, setFresh] = useState(true);

  const digit = (d) => {
    setDisplay((cur) => (fresh || cur === '0' ? d : cur + d));
    setFresh(false);
  };

  const dot = () => {
    setDisplay((cur) => (fresh ? '0.' : cur.includes('.') ? cur : cur + '.'));
    setFresh(false);
  };

  const choose = (next) => {
    const cur = parseFloat(display);
    if (op !== null && !fresh) {
      const r = compute(operand, cur, op);
      setDisplay(String(r));
      setOperand(r);
    } else {
      setOperand(cur);
    }
    setOp(next);
    setFresh(true);
  };

  const equals = () => {
    if (op === null) return;
    const r = compute(operand, parseFloat(display), op);
    setDisplay(Number.isNaN(r) ? 'Error' : String(r));
    setOperand(null);
    setOp(null);
    setFresh(true);
  };

  const clear = () => {
    setDisplay('0');
    setOperand(null);
    setOp(null);
    setFresh(true);
  };

  const Btn = ({ children, onClick, span, bg }) => (
    <button
      onClick={onClick}
      style={{ gridColumn: span ? `span ${span}` : undefined, padding: 16, fontSize: 18, cursor: 'pointer', border: '1px solid #e5e7eb', borderRadius: 8, background: bg || '#fff' }}
    >
      {children}
    </button>
  );

  return (
    <div style={{ width: 260 }}>
      <div style={{ textAlign: 'right', padding: 16, fontSize: 28, background: '#111827', color: '#fff', borderRadius: 8, marginBottom: 8, fontFamily: 'monospace', overflow: 'hidden' }}>
        {display}
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 8 }}>
        <Btn onClick={clear} span={2} bg="#fee2e2">C</Btn>
        <Btn onClick={() => choose('/')} bg="#eef2ff">÷</Btn>
        <Btn onClick={() => choose('*')} bg="#eef2ff">×</Btn>
        {['7', '8', '9'].map((d) => <Btn key={d} onClick={() => digit(d)}>{d}</Btn>)}
        <Btn onClick={() => choose('-')} bg="#eef2ff">−</Btn>
        {['4', '5', '6'].map((d) => <Btn key={d} onClick={() => digit(d)}>{d}</Btn>)}
        <Btn onClick={() => choose('+')} bg="#eef2ff">+</Btn>
        {['1', '2', '3'].map((d) => <Btn key={d} onClick={() => digit(d)}>{d}</Btn>)}
        <Btn onClick={equals} bg="#2563eb">=</Btn>
        <Btn onClick={() => digit('0')} span={2}>0</Btn>
        <Btn onClick={dot}>.</Btn>
      </div>
    </div>
  );
}

