import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-calculator',
  template: `
    <div style="width: 260px;">
      <div style="text-align: right; padding: 16px; font-size: 28px; background: #111827; color: #fff; border-radius: 8px; margin-bottom: 8px; font-family: monospace; overflow: hidden;">{{ display }}</div>
      <div style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px;">
        <button (click)="clear()" style="grid-column: span 2; background: #fee2e2;" class="key">C</button>
        <button (click)="choose('/')" style="background: #eef2ff;" class="key">÷</button>
        <button (click)="choose('*')" style="background: #eef2ff;" class="key">×</button>
        <button (click)="digit('7')" class="key">7</button>
        <button (click)="digit('8')" class="key">8</button>
        <button (click)="digit('9')" class="key">9</button>
        <button (click)="choose('-')" style="background: #eef2ff;" class="key">−</button>
        <button (click)="digit('4')" class="key">4</button>
        <button (click)="digit('5')" class="key">5</button>
        <button (click)="digit('6')" class="key">6</button>
        <button (click)="choose('+')" style="background: #eef2ff;" class="key">+</button>
        <button (click)="digit('1')" class="key">1</button>
        <button (click)="digit('2')" class="key">2</button>
        <button (click)="digit('3')" class="key">3</button>
        <button (click)="equals()" style="background: #2563eb; color: #fff;" class="key">=</button>
        <button (click)="digit('0')" style="grid-column: span 2;" class="key">0</button>
        <button (click)="dot()" class="key">.</button>
      </div>
    </div>
  `,
  styles: [`
    .key { padding: 16px; font-size: 18px; cursor: pointer; border: 1px solid #e5e7eb; border-radius: 8px; background: #fff; }
  `],
})
export class CalculatorComponent {
  display = '0';
  operand: number | null = null;
  op: string | null = null;
  fresh = true;

  compute(a: number, b: number, op: string): number {
    if (op === '+') return a + b;
    if (op === '-') return a - b;
    if (op === '*') return a * b;
    if (op === '/') return b === 0 ? NaN : a / b;
    return b;
  }

  digit(d: string): void {
    this.display = this.fresh || this.display === '0' ? d : this.display + d;
    this.fresh = false;
  }

  dot(): void {
    if (this.fresh) {
      this.display = '0.';
    } else if (this.display.indexOf('.') === -1) {
      this.display += '.';
    }
    this.fresh = false;
  }

  choose(next: string): void {
    const cur = parseFloat(this.display);
    if (this.op !== null && !this.fresh) {
      const r = this.compute(this.operand as number, cur, this.op);
      this.display = String(r);
      this.operand = r;
    } else {
      this.operand = cur;
    }
    this.op = next;
    this.fresh = true;
  }

  equals(): void {
    if (this.op === null) {
      return;
    }
    const r = this.compute(this.operand as number, parseFloat(this.display), this.op);
    this.display = Number.isNaN(r) ? 'Error' : String(r);
    this.operand = null;
    this.op = null;
    this.fresh = true;
  }

  clear(): void {
    this.display = '0';
    this.operand = null;
    this.op = null;
    this.fresh = true;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Calculator Demo</h1>
      <app-calculator></app-calculator>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, CalculatorComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
